142→pub async fn get_next_actions(
143→    AuthenticatedUser(user_id): AuthenticatedUser,
144→    State(pool): State<PgPool>,
145→    headers: HeaderMap,
146→    Query(filter): Query<ContextFilter>,
147→) -> Result<Response, NextActionError> {
148→    let htmx = is_htmx_request(&headers);
149→
150→    let contexts = context_service::list_contexts(&pool, &user_id)
151→        .await
152→        .map_err(NextActionError::Unexpected)?;
153→
154→    let actions = if let Some(ctx_uuid) = filter.context {
155→        let ctx_id = ContextId::from_uuid(ctx_uuid);
156→        next_action_service::list_active_next_actions_by_context(&pool, &user_id, &ctx_id)
157→            .await
158→            .map_err(NextActionError::Unexpected)?
159→    } else {
160→        next_action_service::list_active_next_actions(&pool, &user_id)
161→            .await
162→            .map_err(NextActionError::Unexpected)?
163→    };
164→
165→    let show_headings = filter.context.is_none();
166→    let groups = build_context_groups(&actions, &contexts, filter.context.is_some());
167→
168→    // HTMX filter requests: return just the action list fragment
169→    if htmx {
170→        let template = NextActionListTemplate {
171→            groups,
172→            show_headings,
173→        };
174→        let body = template.render().map_err(NextActionError::Render)?;
175→        return Ok(Html(body).into_response());
176→    }
177→
178→    let inbox_count = inbox_service::get_inbox_count(&pool, &user_id)
179→        .await
180→        .map_err(NextActionError::Unexpected)?;
181→
182→    let context_options: Vec<ContextOption> = contexts
183→        .iter()
184→        .map(|c| ContextOption {
185→            id: c.id().as_uuid().to_string(),
186→            name: c.name().as_str().to_string(),
187→        })
188→        .collect();
189→
190→    let selected_context = filter.context.map(|c| c.to_string());
191→
192→    let template = NextActionsTemplate {
193→        current_page: "next_actions",
194→        inbox_count,
195→        groups,
196→        contexts: context_options,
197→        selected_context,
198→        error_message: None,
199→    };
200→    Ok(Html(template.render()?).into_response())
201→}
