209→pub async fn post_next_action(
210→    AuthenticatedUser(user_id): AuthenticatedUser,
211→    State(pool): State<PgPool>,
212→    headers: HeaderMap,
213→    Form(form): Form<AddNextActionForm>,
214→) -> Result<Response, NextActionError> {
215→    let htmx = is_htmx_request(&headers);
216→
217→    if form.title.trim().is_empty() {
218→        if htmx {
219→            return Ok(StatusCode::NO_CONTENT.into_response());
220→        }
221→        return Ok(Redirect::to("/next-actions").into_response());
222→    }
223→
224→    let context_id = ContextId::from_uuid(form.context_id);
225→
226→    let contexts = context_service::list_contexts(&pool, &user_id)
227→        .await
228→        .map_err(NextActionError::Unexpected)?;
229→
230→    match next_action_service::add_next_action(&pool, user_id.clone(), context_id, form.title).await
231→    {
232→        Ok(action) => {
233→            if htmx {
234→                let template = NextActionItemTemplate {
235→                    action: build_action_view(&action, &contexts),
236→                };
237→                let body = template.render().map_err(NextActionError::Render)?;
238→                Ok(htmx_response_with_announce(Html(body), "Next action added"))
239→            } else {
240→                Ok(Redirect::to("/next-actions").into_response())
241→            }
242→        }
243→        Err(AddNextActionError::InvalidTitle(title_err)) => {
244→            let user_facing = match title_err {
245→                TodoTitleError::Empty => {
246→                    if htmx {
247→                        return Ok(StatusCode::NO_CONTENT.into_response());
248→                    }
249→                    return Ok(Redirect::to("/next-actions").into_response());
250→                }
251→                TodoTitleError::TooLong { max, .. } => {
252→                    format!("That title is too long (max {max} characters)")
253→                }
254→            };
255→
256→            render_next_actions_with_error(&pool, &user_id, &user_facing).await
257→        }
258→        Err(AddNextActionError::Unexpected(err)) => Err(NextActionError::Unexpected(err)),
259→    }
260→}
