189→    let inbox_count = inbox_service::get_inbox_count(pool, user_id)
190→        .await
191→        .map_err(ProjectError::Unexpected)?;
192→
193→    let projects = project_service::list_active_projects(pool, user_id)
194→        .await
195→        .map_err(ProjectError::Unexpected)?;
196→
197→    let mut project_views = Vec::new();
198→    for project in &projects {
199→        let count = crate::infrastructure::project_repository::count_project_next_actions(
200→            pool,
201→            project.id(),
202→        )
203→        .await
204→        .map_err(|e| ProjectError::Unexpected(anyhow::anyhow!("Database error: {e}")))?;
205→        project_views.push(build_project_view(project, count));
206→    }
207→
208→    let template = ProjectsTemplate {
