}

#[derive(Template)]
#[template(path = "next_actions.html")]
struct NextActionsTemplate {
    current_page: &'static str,
    inbox_count: i64,
    groups: Vec<ContextGroup>,
    contexts: Vec<ContextOption>,
    selected_context: Option<String>,
