 68→fn build_action_view(
 69→    action: &NextAction,
 70→    contexts: &[Context],
 71→    projects: &[Project],
 72→) -> NextActionView {
 73→    let context_name = contexts
 74→        .iter()
 75→        .find(|c| c.id() == action.context_id())
 76→        .map(|c| c.name().as_str().to_string())
 77→        .unwrap_or_else(|| "Unknown".to_string());
 78→
 79→    let project_name = action.project_id().and_then(|pid| {
 80→        projects
 81→            .iter()
 82→            .find(|p| p.id() == pid)
 83→            .map(|p| p.title().as_str().to_string())
 84→    });
 85→
 86→    NextActionView {
 87→        id: action.id().as_uuid().to_string(),
 88→        title: action.title().as_str().to_string(),
 89→        context_name,
 90→        project_name,
 91→    }
 92→}
 93→
 94→fn build_context_groups(
 95→    actions: &[NextAction],
 96→    contexts: &[Context],
 97→    projects: &[Project],
 98→    single_context: bool,
 99→) -> Vec<ContextGroup> {
100→    if single_context {
101→        // When filtering by a single context, put all actions in one group
102→        // (the heading is redundant since the filter pill already shows it)
103→        let context_name = actions
104→            .first()
105→            .and_then(|a| {
106→                contexts
107→                    .iter()
108→                    .find(|c| c.id() == a.context_id())
109→                    .map(|c| c.name().as_str().to_string())
110→            })
111→            .unwrap_or_default();
112→
113→        let context_id = actions
114→            .first()
115→            .map(|a| a.context_id().as_uuid().to_string())
116→            .unwrap_or_default();
117→
118→        let action_views = actions
119→            .iter()
120→            .map(|a| build_action_view(a, contexts, projects))
121→            .collect();
122→
123→        return vec![ContextGroup {
124→            context_name,
125→            context_id,
126→            actions: action_views,
127→        }];
128→    }
129→
130→    // "All" view: group actions by context, preserving context order
131→    let mut groups: Vec<ContextGroup> = Vec::new();
132→
133→    for ctx in contexts {
134→        let ctx_actions: Vec<NextActionView> = actions
135→            .iter()
136→            .filter(|a| a.context_id() == ctx.id())
137→            .map(|a| build_action_view(a, contexts, projects))
138→            .collect();
139→
140→        if !ctx_actions.is_empty() {
141→            groups.push(ContextGroup {
142→                context_name: ctx.name().as_str().to_string(),
143→                context_id: ctx.id().as_uuid().to_string(),
144→                actions: ctx_actions,
145→            });
146→        }
147→    }
148→
149→    groups
150→}
