                .ok_or_else(|| {
                    NextActionError::Unexpected(anyhow::anyhow!("Next action not found"))
                })?;

                let contexts = context_service::list_contexts(&pool, &user_id)
                    .await
                    .map_err(NextActionError::Unexpected)?;

                let template = NextActionItemTemplate {
